def parse_theta_results(fname):
    with open(fname) as handle:
        lines = [line.strip() for line in handle if line.strip()]
        if len(lines) < 2:
            raise ValueError('File must contain header and data line')
        header = lines[0].split('\t')
        body = lines[1].split('\t')
        # Pad body to 4 columns if missing
        while len(body) < 4:
            body.append('')
        nll_str = body[0].strip()
        if nll_str == '':
            raise ValueError('NLL must not be empty')
        nll = float(nll_str)
        mu_str = body[1].strip()
        if mu_str == '':
            mu_normal = None
            mu_tumors = []
        else:
            mu = mu_str.split(',')
            mu_normal = float(mu[0]) if mu[0] else None
            mu_tumors = [float(x) for x in mu[1:] if x]  # skip empty
        C_str = body[2].strip()
        probs_str = body[3].strip()
        if C_str == '':
            copies = []
        else:
            copies = C_str.split(':')
            if len(mu_tumors) == 1 or len(mu_tumors) == 0:
                copies = [[int(c) if c.isdigit() else None for c in copies]]
            else:
                copies = [[int(c) if c.isdigit() else None for c in subcop] for subcop in zip(*[c.split(',') for c in copies])]
        if probs_str == '':
            probs = []
        else:
            probs_list = probs_str.split(',')
            if len(mu_tumors) == 1 or len(mu_tumors) == 0:
                probs = [float(p) if p and not p.isalpha() else None for p in probs_list]
            else:
                probs = [[float(p) if p and not p.isalpha() else None for p in subprob] for subprob in zip(*[p.split(',') for p in probs_list])]
    return {'NLL': nll, 'mu_normal': mu_normal, 'mu_tumors': mu_tumors, 'C': copies, 'p*': probs}
